zvob_hash_capture() {
  local z_file="$1"

  if command -v sha256sum >/dev/null 2>&1; then
    sha256sum "${z_file}" | awk '{print $1}'
  elif command -v shasum >/dev/null 2>&1; then
    shasum -a 256 "${z_file}" | awk '{print $1}'
  else
    return 1
  fi
}

zvob_commit_capture() {
  git rev-parse HEAD 2>/dev/null || echo "unknown"
}

